// server/trpc.ts
const createContext = async ({ req }: CreateNextContextOptions) => {
  const token = req.headers.authorization?.split(' ')[1];
  let user: JWTPayload | null = null;
  if (token) {
    try { user = (await jwtVerify(token, secret)).payload; }
    catch { /* invalid token — user stays null */ }
  }
  return { user };
};

const authedProcedure = t.procedure.use(({ ctx, next }) => {
  if (!ctx.user) throw new TRPCError({ code: 'UNAUTHORIZED' });
  return next({ ctx: { user: ctx.user } }); // narrows type to non-null
});

