export const ordersRouter = router({
  create: t.procedure
    .input(z.object({
      idempotencyKey: z.string().uuid(),
      items: z.array(z.object({ productId: z.string(), qty: z.number() })),
    }))
    .mutation(async ({ input, ctx }) => {
      const cached = await ctx.redis.get(`order:create:${input.idempotencyKey}`);
      if (cached) return JSON.parse(cached);

      const order = await ctx.db.order.create({ data: { items: input.items } });
      await ctx.redis.setex(`order:create:${input.idempotencyKey}`, 86400, JSON.stringify(order));
      return order;
    }),
});

import { z } from 'zod';
import { TRPCError } from '@trpc/server';
import { t } from './trpc-init';

// Enforce origin for CSRF protection on mutations
const csrfMiddleware = t.middleware(({ ctx, next }) => {
  const origin = ctx.req.headers['origin'];
  if (!origin || !process.env.ALLOWED_ORIGINS!.split(',').includes(origin)) {
    throw new TRPCError({ code: 'FORBIDDEN', message: 'Invalid origin' });
  }
  return next();
});

export const secureProcedure = t.procedure.use(csrfMiddleware);

export const updateProfileRouter = t.router({
  update: secureProcedure
